     1→// FreeLang v6: Lexer
     2→
     3→import { Token, TokenType as T } from "./token";
     4→
     5→const KEYWORDS: Record<string, T> = {
     6→  let: T.Let, const: T.Const, fn: T.Fn, return: T.Return,
     7→  if: T.If, else: T.Else, while: T.While, for: T.For, in: T.In,
     8→  break: T.Break, continue: T.Continue,
     9→  print: T.Print, println: T.Println,
    10→  true: T.Bool, false: T.Bool, null: T.Null,
    11→  try: T.Try, catch: T.Catch, finally: T.Finally, throw: T.Throw,
    12→  import: T.Import, export: T.Export, from: T.From, as: T.As,
    13→  struct: T.Struct, new: T.New, match: T.Match,
    14→  and: T.And, or: T.Or, not: T.Not,
    15→};
    16→
    17→export function lex(source: string): Token[] {
    18→  const tokens: Token[] = [];
    19→  let i = 0, line = 1, col = 1;
    20→
    21→  while (i < source.length) {
    22→    const ch = source[i];
    23→
    24→    // Whitespace
    25→    if (ch === " " || ch === "\t" || ch === "\r") { i++; col++; continue; }
    26→    if (ch === "\n") { i++; line++; col = 1; continue; }
    27→
    28→    // Comment
    29→    if (ch === "/" && source[i + 1] === "/") {
    30→      while (i < source.length && source[i] !== "\n") i++;
    31→      continue;
    32→    }
    33→
    34→    // Number
    35→    if (isDigit(ch)) {
    36→      const start = i;
    37→      while (i < source.length && (isDigit(source[i]) || source[i] === ".")) i++;
    38→      tokens.push({ type: T.Number, value: source.slice(start, i), line, col });
    39→      col += i - start;
    40→      continue;
    41→    }
    42→
    43→    // String
    44→    if (ch === '"' || ch === "'") {
    45→      const quote = ch;
    46→      i++; col++;
    47→
    48→      // Collect parts for potential interpolation
    49→      type Part = { kind: "str"; value: string } | { kind: "expr"; text: string };
    50→      const parts: Part[] = [];
    51→      let str = "";
    52→      let hasInterp = false;
    53→
    54→      while (i < source.length && source[i] !== quote) {
    55→        if (source[i] === "\\" && i + 1 < source.length) {
    56→          i++; col++;
    57→          const esc = source[i];
    58→          switch (esc) {
    59→            case "n": str += "\n"; break;
    60→            case "t": str += "\t"; break;
    61→            case "r": str += "\r"; break;
    62→            case "\\": str += "\\"; break;
    63→            case '"': str += '"'; break;
    64→            case "'": str += "'"; break;
    65→            case "0": str += "\0"; break;
    66→            default: str += esc; break;
    67→          }
    68→          i++; col++;
    69→        } else if (quote === '"' && source[i] === "$" && i + 1 < source.length && source[i + 1] === "{") {
    70→          hasInterp = true;
    71→          parts.push({ kind: "str", value: str });
    72→          str = "";
    73→          i += 2; col += 2; // skip ${
    74→          let depth = 1;
    75→          const exprStart = i;
    76→          while (i < source.length && depth > 0) {
    77→            if (source[i] === "{") depth++;
    78→            else if (source[i] === "}") { depth--; if (depth === 0) break; }
    79→            i++; col++;
    80→          }
    81→          parts.push({ kind: "expr", text: source.slice(exprStart, i) });
    82→          i++; col++; // skip }
    83→        } else {
    84→          str += source[i];
    85→          i++; col++;
    86→        }
    87→      }
    88→      i++; col++; // skip closing quote
    89→
    90→      if (!hasInterp) {
    91→        tokens.push({ type: T.String, value: str, line, col });
    92→      } else {
    93→        // Emit remaining string
    94→        parts.push({ kind: "str", value: str });
    95→        // Desugar to concatenation: ("str" + (expr) + "str" ...)
    96→        tokens.push({ type: T.LParen, value: "(", line, col });
    97→        let first = true;
    98→        for (const part of parts) {
    99→          if (!first) tokens.push({ type: T.Plus, value: "+", line, col });
   100→          if (part.kind === "str") {
   101→            tokens.push({ type: T.String, value: part.value, line, col });
   102→          } else {
   103→            tokens.push({ type: T.LParen, value: "(", line, col });
   104→            const inner = lex(part.text);
   105→            inner.pop(); // remove EOF
   106→            tokens.push(...inner);
   107→            tokens.push({ type: T.RParen, value: ")", line, col });
   108→          }
   109→          first = false;
   110→        }
   111→        tokens.push({ type: T.RParen, value: ")", line, col });
   112→      }
   113→      continue;
   114→    }
   115→
   116→    // Ident / Keyword
   117→    if (isAlpha(ch)) {
   118→      const start = i;
   119→      while (i < source.length && isAlphaNum(source[i])) i++;
   120→      const word = source.slice(start, i);
   121→      tokens.push({ type: KEYWORDS[word] ?? T.Ident, value: word, line, col });
   122→      col += i - start;
   123→      continue;
   124→    }
   125→
   126→    // Operators & Delimiters
   127→    const startCol = col;
   128→    switch (ch) {
   129→      case "+": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.PlusAssign, "+=")) : tok(T.Plus, "+")); break;
   130→      case "-": tokens.push(source[i+1] === ">" ? (i++, col++, tok(T.Arrow, "->")) : source[i+1] === "=" ? (i++, col++, tok(T.MinusAssign, "-=")) : tok(T.Minus, "-")); break;
   131→      case "*": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.StarAssign, "*=")) : tok(T.Star, "*")); break;
   132→      case "/": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.SlashAssign, "/=")) : tok(T.Slash, "/")); break;
   133→      case "%": tokens.push(tok(T.Percent, "%")); break;
   134→      case "=": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Eq, "==")) : source[i+1] === ">" ? (i++, col++, tok(T.FatArrow, "=>")) : tok(T.Assign, "=")); break;
   135→      case "!": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Neq, "!=")) : tok(T.Not, "!")); break;
   136→      case "<": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Lte, "<=")) : tok(T.Lt, "<")); break;
   137→      case ">": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Gte, ">=")) : tok(T.Gt, ">")); break;
   138→      case "&": if (source[i+1] === "&") { i++; col++; tokens.push(tok(T.And, "&&")); } break;
   139→      case "|": if (source[i+1] === "|") { i++; col++; tokens.push(tok(T.Or, "||")); } break;
   140→      case "(": tokens.push(tok(T.LParen, "(")); break;
   141→      case ")": tokens.push(tok(T.RParen, ")")); break;
   142→      case "{": tokens.push(tok(T.LBrace, "{")); break;
   143→      case "}": tokens.push(tok(T.RBrace, "}")); break;
   144→      case "[": tokens.push(tok(T.LBracket, "[")); break;
   145→      case "]": tokens.push(tok(T.RBracket, "]")); break;
   146→      case ",": tokens.push(tok(T.Comma, ",")); break;
   147→      case ";": tokens.push(tok(T.Semicolon, ";")); break;
   148→      case ":": tokens.push(tok(T.Colon, ":")); break;
   149→      case ".": tokens.push(source[i+1] === "." ? (i++, col++, tok(T.DotDot, "..")) : tok(T.Dot, ".")); break;
   150→      default: throw new Error(`Unexpected character '${ch}' at line ${line}:${col}`);
   151→    }
   152→    i++; col++;
   153→
   154→    function tok(type: T, value: string): Token {
   155→      return { type, value, line, col: startCol };
   156→    }
   157→  }
   158→
   159→  tokens.push({ type: T.EOF, value: "", line, col });
   160→  return tokens;
   161→}
   162→
   163→function isDigit(ch: string): boolean { return ch >= "0" && ch <= "9"; }
   164→function isAlpha(ch: string): boolean { return (ch >= "a" && ch <= "z") || (ch >= "A" && ch <= "Z") || ch === "_"; }
   165→function isAlphaNum(ch: string): boolean { return isAlpha(ch) || isDigit(ch); }
   166→

