     1→// FreeLang v6: Parser (Pratt / Recursive Descent)
     2→
     3→import { Token, TokenType as T } from "./token";
     4→import { Expr, Stmt, Program, MatchArm } from "./ast";
     5→
     6→export function parse(tokens: Token[]): Program {
     7→  let pos = 0;
     8→
     9→  function peek(): Token { return tokens[pos]; }
    10→  function advance(): Token { return tokens[pos++]; }
    11→  function expect(type: T, msg?: string): Token {
    12→    const t = advance();
    13→    if (t.type !== type) throw new Error(msg ?? `Expected ${T[type]}, got ${T[t.type]} '${t.value}' at line ${t.line}`);
    14→    return t;
    15→  }
    16→  function match(type: T): boolean { if (peek().type === type) { advance(); return true; } return false; }
    17→  function at(type: T): boolean { return peek().type === type; }
    18→
    19→  // --- Statements ---
    20→  function parseProgram(): Program {
    21→    const stmts: Stmt[] = [];
    22→    while (!at(T.EOF)) stmts.push(parseStmt());
    23→    return { stmts };
    24→  }
    25→
    26→  function parseStmt(): Stmt {
    27→    while (match(T.Semicolon)) {} // skip stray semicolons
    28→    if (at(T.EOF)) return { kind: "expr", expr: { kind: "null" } };
    29→    if (at(T.Let) || at(T.Const)) return parseLetStmt();
    30→    if (at(T.Fn)) return parseFnStmt();
    31→    if (at(T.Return)) return parseReturn();
    32→    if (at(T.If)) return parseIf();
    33→    if (at(T.While)) return parseWhile();
    34→    if (at(T.For)) return parseFor();
    35→    if (at(T.LBrace)) return parseBlock();
    36→    if (at(T.Print) || at(T.Println)) return parsePrint();
    37→    if (at(T.Break)) { advance(); match(T.Semicolon); return { kind: "break" }; }
    38→    if (at(T.Continue)) { advance(); match(T.Semicolon); return { kind: "continue" }; }
    39→    if (at(T.Try)) return parseTry();
    40→    if (at(T.Throw)) return parseThrow();
    41→    if (at(T.Struct)) return parseStruct();
    42→    if (at(T.Import)) return parseImport();
    43→    if (at(T.Export)) return parseExport();
    44→    if (at(T.Match)) return parseMatch();
    45→    return parseExprStmt();
    46→  }
    47→
    48→  function parseLetStmt(): Stmt {
    49→    const mutable = advance().type === T.Let;
    50→
    51→    // Object destructuring: let {a, b} = expr
    52→    if (at(T.LBrace)) {
    53→      advance();
    54→      const names: string[] = [];
    55→      while (!at(T.RBrace) && !at(T.EOF)) {
    56→        names.push(expect(T.Ident, "Expected destructured name").value);
    57→        match(T.Comma);
    58→      }
    59→      expect(T.RBrace);
    60→      expect(T.Assign, "Expected '=' after destructuring pattern");
    61→      const init = parseExpr();
    62→      match(T.Semicolon);
    63→      const tmp = `__d${pos}`;
    64→      return { kind: "multi", stmts: [
    65→        { kind: "let", name: tmp, mutable: false, init },
    66→        ...names.map(n => ({
    67→          kind: "let" as const, name: n, mutable,
    68→          init: { kind: "member" as const, object: { kind: "ident" as const, name: tmp }, property: n } as Expr,
    69→        }))
    70→      ]};
    71→    }
    72→
    73→    // Array destructuring: let [x, y] = expr
    74→    if (at(T.LBracket)) {
    75→      advance();
    76→      const names: string[] = [];
    77→      while (!at(T.RBracket) && !at(T.EOF)) {
    78→        names.push(expect(T.Ident, "Expected destructured name").value);
    79→        match(T.Comma);
    80→      }
    81→      expect(T.RBracket);
    82→      expect(T.Assign, "Expected '=' after destructuring pattern");
    83→      const init = parseExpr();
    84→      match(T.Semicolon);
    85→      const tmp = `__d${pos}`;
    86→      return { kind: "multi", stmts: [
    87→        { kind: "let", name: tmp, mutable: false, init },
    88→        ...names.map((n, i) => ({
    89→          kind: "let" as const, name: n, mutable,
    90→          init: { kind: "index" as const, object: { kind: "ident" as const, name: tmp }, index: { kind: "number" as const, value: i } as Expr } as Expr,
    91→        }))
    92→      ]};
    93→    }
    94→
    95→    const name = expect(T.Ident, "Expected variable name").value;
    96→    let init: Expr | null = null;
    97→    if (match(T.Assign)) init = parseExpr();
    98→    match(T.Semicolon);
    99→    return { kind: "let", name, mutable, init };
   100→  }
   101→
   102→  function parseFnStmt(): Stmt {
   103→    advance(); // fn
   104→    const name = expect(T.Ident, "Expected function name").value;
   105→    expect(T.LParen);
   106→    const params = parseParams();
   107→    expect(T.RParen);
   108→    expect(T.LBrace);
   109→    const body = parseBody();
   110→    expect(T.RBrace);
   111→    return { kind: "fn", name, params, body };
   112→  }
   113→
   114→  function parseReturn(): Stmt {
   115→    advance(); // return
   116→    let value: Expr | null = null;
   117→    if (!at(T.Semicolon) && !at(T.RBrace) && !at(T.EOF)) value = parseExpr();
   118→    match(T.Semicolon);
   119→    return { kind: "return", value };
   120→  }
   121→
   122→  function parseIf(): Stmt {
   123→    advance(); // if
   124→    const useParen = match(T.LParen);
   125→    const cond = parseExpr();
   126→    if (useParen) expect(T.RParen);
   127→    expect(T.LBrace);
   128→    const then = parseBody();
   129→    expect(T.RBrace);
   130→    let else_: Stmt[] | null = null;
   131→    if (match(T.Else)) {
   132→      if (at(T.If)) {
   133→        else_ = [parseIf()];
   134→      } else {
   135→        expect(T.LBrace);
   136→        else_ = parseBody();
   137→        expect(T.RBrace);
   138→      }
   139→    }
   140→    return { kind: "if", cond, then, else: else_ };
   141→  }
   142→
   143→  function parseWhile(): Stmt {
   144→    advance(); // while
   145→    const useParen = match(T.LParen);
   146→    const cond = parseExpr();
   147→    if (useParen) expect(T.RParen);
   148→    expect(T.LBrace);
   149→    const body = parseBody();
   150→    expect(T.RBrace);
   151→    return { kind: "while", cond, body };
   152→  }
   153→
   154→  function parseFor(): Stmt {
   155→    advance(); // for
   156→    const name = expect(T.Ident, "Expected loop variable").value;
   157→    expect(T.In, "Expected 'in'");
   158→    const iter = parseExpr();
   159→    expect(T.LBrace);
   160→    const body = parseBody();
   161→    expect(T.RBrace);
   162→    return { kind: "for", name, iter, body };
   163→  }
   164→
   165→  function parseBlock(): Stmt {
   166→    expect(T.LBrace);
   167→    const body = parseBody();
   168→    expect(T.RBrace);
   169→    return { kind: "block", body };
   170→  }
   171→
   172→  function parsePrint(): Stmt {
   173→    const newline = advance().type === T.Println;
   174→    expect(T.LParen);
   175→    const expr = parseExpr();
   176→    expect(T.RParen);
   177→    match(T.Semicolon);
   178→    return { kind: "print", expr, newline };
   179→  }
   180→
   181→  function parseTry(): Stmt {
   182→    advance(); // try
   183→    expect(T.LBrace);
   184→    const body = parseBody();
   185→    expect(T.RBrace);
   186→    let catchVar: string | null = null;
   187→    let catchBody: Stmt[] = [];
   188→    let finallyBody: Stmt[] = [];
   189→    if (match(T.Catch)) {
   190→      if (match(T.LParen)) {
   191→        catchVar = expect(T.Ident, "Expected catch variable").value;
   192→        expect(T.RParen);
   193→      }
   194→      expect(T.LBrace);
   195→      catchBody = parseBody();
   196→      expect(T.RBrace);
   197→    }
   198→    if (match(T.Finally)) {
   199→      expect(T.LBrace);
   200→      finallyBody = parseBody();
   201→      expect(T.RBrace);
   202→    }
   203→    return { kind: "try", body, catchVar, catchBody, finallyBody };
   204→  }
   205→
   206→  function parseThrow(): Stmt {
   207→    advance(); // throw
   208→    const expr = parseExpr();
   209→    match(T.Semicolon);
   210→    return { kind: "throw", expr };
   211→  }
   212→
   213→  function parseStruct(): Stmt {
   214→    advance(); // struct
   215→    const name = expect(T.Ident).value;
   216→    expect(T.LBrace);
   217→    const fields: string[] = [];
   218→    while (!at(T.RBrace) && !at(T.EOF)) {
   219→      fields.push(expect(T.Ident).value);
   220→      match(T.Comma);
   221→    }
   222→    expect(T.RBrace);
   223→    return { kind: "struct", name, fields };
   224→  }
   225→
   226→  function parseImport(): Stmt {
   227→    advance(); // import
   228→    if (at(T.LBrace)) {
   229→      // import { name1, name2 } from "path"
   230→      advance(); // {
   231→      const names: string[] = [];
   232→      while (!at(T.RBrace) && !at(T.EOF)) {
   233→        names.push(expect(T.Ident, "Expected import name").value);
   234→        match(T.Comma);
   235→      }
   236→      expect(T.RBrace);
   237→      expect(T.From, "Expected 'from'");
   238→      const p = expect(T.String, "Expected module path").value;
   239→      match(T.Semicolon);
   240→      return { kind: "import", names, path: p, alias: null };
   241→    } else {
   242→      // import "path" or import "path" as Alias
   243→      const p = expect(T.String, "Expected module path").value;
   244→      let alias: string | null = null;
   245→      if (match(T.As)) alias = expect(T.Ident, "Expected alias name").value;
   246→      match(T.Semicolon);
   247→      return { kind: "import", names: null, path: p, alias };
   248→    }
   249→  }
   250→
   251→  function parseExport(): Stmt {
   252→    advance(); // export
   253→    if (at(T.Fn)) return { kind: "export", stmt: parseFnStmt() };
   254→    if (at(T.Let) || at(T.Const)) return { kind: "export", stmt: parseLetStmt() };
   255→    throw new Error(`Expected fn or let after export at line ${peek().line}`);
   256→  }
   257→
   258→  function parseMatch(): Stmt {
   259→    advance(); // match
   260→    const subject = parseExpr();
   261→    expect(T.LBrace);
   262→    const arms: MatchArm[] = [];
   263→    while (!at(T.RBrace) && !at(T.EOF)) {
   264→      let pattern: Expr | null = null;
   265→      if (at(T.Ident) && peek().value === "_") {
   266→        advance(); // _
   267→      } else {
   268→        pattern = parseExpr();
   269→      }
   270→      expect(T.FatArrow, "Expected '=>' in match arm");
   271→      let body: Stmt[];
   272→      if (at(T.LBrace)) {
   273→        expect(T.LBrace);
   274→        body = parseBody();
   275→        expect(T.RBrace);
   276→      } else {
   277→        body = [parseStmt()];
   278→      }
   279→      arms.push({ pattern, body });
   280→      match(T.Comma);
   281→    }
   282→    expect(T.RBrace);
   283→    return { kind: "match", subject, arms };
   284→  }
   285→
   286→  function parseExprStmt(): Stmt {
   287→    const expr = parseExpr();
   288→    match(T.Semicolon);
   289→    return { kind: "expr", expr };
   290→  }
   291→
   292→  // --- Expressions (Pratt) ---
   293→  function parseExpr(): Expr { return parseAssign(); }
   294→
   295→  function parseAssign(): Expr {
   296→    let left = parseOr();
   297→    if (at(T.Assign) || at(T.PlusAssign) || at(T.MinusAssign) || at(T.StarAssign) || at(T.SlashAssign)) {
   298→      const op = advance();
   299→      const right = parseAssign();
   300→      if (op.type === T.Assign) return { kind: "assign", target: left, value: right };
   301→      const binOp = op.value[0]; // +, -, *, /
   302→      return { kind: "assign", target: left, value: { kind: "binary", op: binOp, left, right } };
   303→    }
   304→    return left;
   305→  }
   306→
   307→  function parseOr(): Expr {
   308→    let left = parseAnd();
   309→    while (match(T.Or)) left = { kind: "binary", op: "||", left, right: parseAnd() };
   310→    return left;
   311→  }
   312→
   313→  function parseAnd(): Expr {
   314→    let left = parseEquality();
   315→    while (match(T.And)) left = { kind: "binary", op: "&&", left, right: parseEquality() };
   316→    return left;
   317→  }
   318→
   319→  function parseEquality(): Expr {
   320→    let left = parseComparison();
   321→    while (at(T.Eq) || at(T.Neq)) {
   322→      const op = advance().value;
   323→      left = { kind: "binary", op, left, right: parseComparison() };
   324→    }
   325→    return left;
   326→  }
   327→
   328→  function parseComparison(): Expr {
   329→    let left = parseAddition();
   330→    while (at(T.Lt) || at(T.Gt) || at(T.Lte) || at(T.Gte)) {
   331→      const op = advance().value;
   332→      left = { kind: "binary", op, left, right: parseAddition() };
   333→    }
   334→    return left;
   335→  }
   336→
   337→  function parseAddition(): Expr {
   338→    let left = parseMultiplication();
   339→    while (at(T.Plus) || at(T.Minus)) {
   340→      const op = advance().value;
   341→      left = { kind: "binary", op, left, right: parseMultiplication() };
   342→    }
   343→    return left;
   344→  }
   345→
   346→  function parseMultiplication(): Expr {
   347→    let left = parseUnary();
   348→    while (at(T.Star) || at(T.Slash) || at(T.Percent)) {
