   411→        const savedPos = pos;
   412→        advance(); // (
   413→
   414→        // Check for empty parens arrow: () => ...
   415→        if (at(T.RParen)) {
   416→          const rp = pos;
   417→          advance(); // )
   418→          if (at(T.FatArrow)) {
   419→            advance(); // =>
   420→            return parseArrowBody([]);
   421→          }
   422→          // Not arrow, backtrack
   423→          pos = savedPos;
   424→          advance();
   425→          const expr = parseExpr();
   426→          expect(T.RParen);
   427→          return expr;
   428→        }
   429→
   430→        // Try parsing as ident list for arrow function
   431→        let isArrow = true;
   432→        const params: string[] = [];
   433→        const tryPos = pos;
   434→        while (!at(T.RParen) && !at(T.EOF)) {
   435→          if (!at(T.Ident)) { isArrow = false; break; }
