   437→          if (!at(T.RParen)) {
   438→            if (!match(T.Comma)) { isArrow = false; break; }
   439→          }
   440→        }
   441→        if (isArrow && at(T.RParen)) {
   442→          advance(); // )
   443→          if (at(T.FatArrow)) {
   444→            advance(); // =>
   445→            return parseArrowBody(params);
   446→          }
   447→        }
   448→
   449→        // Not arrow, backtrack and parse as grouped expression
   450→        pos = savedPos;
   451→        advance(); // (
   452→        const expr = parseExpr();
   453→        expect(T.RParen);
   454→        return expr;
   455→      }
   456→      case T.LBracket: return parseArrayLiteral();
   457→      case T.LBrace: return parseObjectLiteral();
   458→      case T.Fn: return parseFnExpr();
   459→      default: throw new Error(`Unexpected token '${t.value}' at line ${t.line}:${t.col}`);
   460→    }
   461→  }
   462→
   463→  function parseArrowBody(params: string[]): Expr {
   464→    if (at(T.LBrace)) {
   465→      expect(T.LBrace);
   466→      const body = parseBody();
   467→      expect(T.RBrace);
   468→      return { kind: "fn", name: null, params, body };
   469→    }
   470→    const expr = parseAssign();
   471→    return { kind: "fn", name: null, params, body: [{ kind: "return", value: expr }] };
   472→  }
   473→
   474→  function parseArrayLiteral(): Expr {
   475→    advance(); // [
   476→    const elements: Expr[] = [];
   477→    while (!at(T.RBracket) && !at(T.EOF)) {
   478→      elements.push(parseExpr());
   479→      match(T.Comma);
   480→    }
   481→    expect(T.RBracket);
   482→    return { kind: "array", elements };
   483→  }
   484→
   485→  function parseObjectLiteral(): Expr {
   486→    advance(); // {
   487→    const entries: { key: string; value: Expr }[] = [];
   488→    while (!at(T.RBrace) && !at(T.EOF)) {
   489→      const key = expect(T.Ident, "Expected key").value;
   490→      expect(T.Colon);
   491→      const value = parseExpr();
   492→      entries.push({ key, value });
   493→      match(T.Comma);
   494→    }
   495→    expect(T.RBrace);
   496→    return { kind: "object", entries };
   497→  }
   498→
   499→  function parseFnExpr(): Expr {
   500→    advance(); // fn
   501→    let name: string | null = null;
   502→    if (at(T.Ident)) name = advance().value;
   503→    expect(T.LParen);
   504→    const params = parseParams();
   505→    expect(T.RParen);
   506→    expect(T.LBrace);
   507→    const body = parseBody();
   508→    expect(T.RBrace);
   509→    return { kind: "fn", name, params, body };
   510→  }
   511→
   512→  function parseParams(): string[] {
   513→    const params: string[] = [];
   514→    while (!at(T.RParen) && !at(T.EOF)) {
   515→      params.push(expect(T.Ident, "Expected parameter name").value);
   516→      match(T.Comma);
   517→    }
   518→    return params;
   519→  }
   520→
   521→  function parseBody(): Stmt[] {
   522→    const stmts: Stmt[] = [];
   523→    while (!at(T.RBrace) && !at(T.EOF)) stmts.push(parseStmt());
   524→    return stmts;
   525→  }
   526→
   527→  return parseProgram();
   528→}
