    21→
    22→export type Value =
    23→  | { tag: "num"; val: number }
    24→  | { tag: "str"; val: string }
    25→  | { tag: "bool"; val: boolean }
    26→  | { tag: "null" }
    27→  | { tag: "array"; val: Value[] }
    28→  | { tag: "object"; val: Map<string, Value> }
    29→  | { tag: "fn"; name: string; arity: number; addr: number; freeVars: Value[] }
    30→  | { tag: "builtin"; name: string }
    31→  | { tag: "iter"; val: Value[]; idx: number };
    32→
    33→export type Chunk = {
    34→  code: number[];
    35→  constants: Value[];
    36→  lines: number[];
    37→};
    38→
    39→type Local = { name: string; depth: number };
    40→type Upvalue = { name: string; isLocal: boolean; index: number };
    41→type CompilerScope = {
    42→  locals: Local[];
    43→  depth: number;
    44→  upvalues: Upvalue[];
    45→};
    46→
    47→type LoopInfo = { startAddr: number; breakPatches: number[] };
    48→
    49→export function compile(program: Program): Chunk {
    50→  const chunk: Chunk = { code: [], constants: [], lines: [] };
    51→  const scopes: CompilerScope[] = [{ locals: [], depth: 0, upvalues: [] }];
    52→  const globals = new Set<string>();
    53→  const loopStack: LoopInfo[] = [];
    54→
    55→  function emit(op: Op, line = 0) { chunk.code.push(op); chunk.lines.push(line); }
    56→  function emitArg(op: Op, arg: number, line = 0) { emit(op, line); chunk.code.push(arg); chunk.lines.push(line); }
    57→  function addConst(val: Value): number {
    58→    chunk.constants.push(val);
    59→    return chunk.constants.length - 1;
    60→  }
    61→  function currentPos(): number { return chunk.code.length; }
    62→  function patchJump(pos: number) { chunk.code[pos + 1] = currentPos(); }
    63→
    64→  function scope(): CompilerScope { return scopes[scopes.length - 1]; }
    65→
    66→  function resolveLocal(name: string): number {
    67→    const locals = scope().locals;
    68→    for (let i = locals.length - 1; i >= 0; i--) {
    69→      if (locals[i].name === name) return i;
    70→    }
    71→    return -1;
    72→  }
    73→
    74→  function declareLocal(name: string) {
    75→    scope().locals.push({ name, depth: scope().depth });
    76→  }
    77→
    78→  function resolveUpvalue(name: string): number {
    79→    if (scopes.length < 2) return -1;
    80→    const s = scope();
    81→    for (let i = 0; i < s.upvalues.length; i++) {
    82→      if (s.upvalues[i].name === name) return i;
    83→    }
    84→    const parent = scopes[scopes.length - 2];
    85→    for (let j = parent.locals.length - 1; j >= 0; j--) {
    86→      if (parent.locals[j].name === name) {
    87→        s.upvalues.push({ name, isLocal: true, index: j });
    88→        return s.upvalues.length - 1;
    89→      }
    90→    }
    91→    for (let j = 0; j < parent.upvalues.length; j++) {
    92→      if (parent.upvalues[j].name === name) {
    93→        s.upvalues.push({ name, isLocal: false, index: j });
    94→        return s.upvalues.length - 1;
    95→      }
    96→    }
    97→    return -1;
    98→  }
    99→
   100→  function compileStmts(stmts: Stmt[]) {
