   111→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   112→        } else {
   113→          declareLocal(s.name);
   114→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   115→        }
   116→        break;
   117→      }
   118→      case "fn": {
   119→        if (scope().depth === 0) globals.add(s.name);
