   125→        break;
   126→      }
   127→      case "return": {
   128→        if (s.value) compileExpr(s.value); else emitArg(Op.Const, addConst({ tag: "null" }));
   129→        emit(Op.Return);
   130→        break;
   131→      }
   132→      case "if": {
   133→        compileExpr(s.cond);
   134→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   135→        compileStmts(s.then);
   136→        if (s.else) {
   137→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   138→          patchJump(jumpFalse);
   139→          compileStmts(s.else);
   140→          patchJump(jumpEnd);
   141→        } else {
