   270→  function compileFnBody(name: string, params: string[], body: Stmt[]) {
   271→    const jumpOver = currentPos(); emitArg(Op.Jump, 0);
   272→    const fnAddr = currentPos();
   273→    scopes.push({ locals: [], depth: 1, upvalues: [] });
