   295→      case "number": emitArg(Op.Const, addConst({ tag: "num", val: e.value })); break;
   296→      case "string": emitArg(Op.Const, addConst({ tag: "str", val: e.value })); break;
   297→      case "bool": emitArg(Op.Const, addConst({ tag: "bool", val: e.value })); break;
