import { run } from "../src/index";

describe("Security Tests", () => {
  describe("Command Injection Prevention", () => {
    test("http_get_sync should not execute shell commands", () => {
      // 셸 메타문자 포함 URL
      const malicious = 'http://example.com"; echo "hacked';
      const result = run(`
        let url = "${malicious}";
        let response = http_get_sync(url);
        println(response)
      `);

      // null이 반환되거나 안전한 처리
      expect(result).toBeDefined();
    });

    test("http_post_sync should not execute shell commands in body", () => {
      const malicious = "'; whoami; echo '";
      const result = run(`
        let body = "${malicious}";
        let response = http_post_sync("http://example.com", body);
        println(response)
      `);

