## 2️⃣ 우선 조치 (1주일 내)

### 2.1 Path Traversal 방어

파일: `src/stdlib/builtin-file.ts` (모든 파일 함수)

```typescript
import * as path from 'path';
import * as fs from 'fs';

// 검증 함수 추가
function validateFilePath(filePath: string, baseDir?: string): string {
  const base = baseDir || process.cwd();
  const normalizedBase = path.resolve(base);

  // 경로 정규화
  let resolved = path.resolve(base, filePath);

  // 심볼릭 링크 해석
  try {
    resolved = fs.realpathSync(resolved);
  } catch {
    // 파일이 없으면 그냥 진행 (writeFile의 경우)
    resolved = path.resolve(base, filePath);
  }

  // 베이스 디렉토리 벗어남 확인
  if (!resolved.startsWith(normalizedBase + path.sep) && resolved !== normalizedBase) {
    throw new Error(`Path traversal attempt: ${filePath}`);
  }

  return resolved;
}

// 개선된 file_read
registerBuiltin("file_read", (args) => {
  try {
    const filePath = strVal(args[0]);
    const baseDir = strVal(args[1] || "./data");

    const validated = validateFilePath(filePath, baseDir);
    return str(fs.readFileSync(validated, "utf-8"));
  } catch (e) {
    return { tag: "null" } as Value;
  }
});

// 개선된 file_write
registerBuiltin("file_write", (args) => {
  try {
    const filePath = strVal(args[0]);
    const content = strVal(args[1]);
    const baseDir = strVal(args[2] || "./data");

    const validated = validateFilePath(filePath, baseDir);

    // 디렉토리 자동 생성
    const dir = path.dirname(validated);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    fs.writeFileSync(validated, content, "utf-8");
    return bool(true);
  } catch (e) {
    return bool(false);
  }
});

// 개선된 file_delete
registerBuiltin("file_delete", (args) => {
  try {
    const filePath = strVal(args[0]);
    const baseDir = strVal(args[1] || "./data");

    const validated = validateFilePath(filePath, baseDir);
    fs.unlinkSync(validated);
    return bool(true);
  } catch (e) {
    return bool(false);
  }
});
```

