### 2.3 설정 검증 추가

파일: `src/stdlib/builtin-config.ts`

```typescript
// 간단한 스키마 검증
function validateConfig(obj: any, allowedKeys?: string[]): boolean {
  // 프로토타입 오염 확인
  if (Object.prototype.hasOwnProperty.call(obj, '__proto__')) {
    return false;
  }
  if (Object.prototype.hasOwnProperty.call(obj, 'constructor')) {
    return false;
  }

  // 키 화이트리스트 검증
  if (allowedKeys) {
    for (const key of Object.keys(obj)) {
      if (!allowedKeys.includes(key)) {
        return false;
      }
    }
  }

  return true;
}

registerBuiltin("config_load", (args) => {
  try {
    const filePath = strVal(args[0]);
    const allowedKeys = args[1]?.tag === "array"
      ? args[1].val.map(v => v.tag === "str" ? v.val : "")
      : undefined;

    const content = fs.readFileSync(filePath, "utf-8");
    const obj = JSON.parse(content);

    if (!validateConfig(obj, allowedKeys)) {
      throw new Error("Invalid configuration");
    }

    return { tag: "object", val: new Map(Object.entries(obj)) };
  } catch (e) {
    return { tag: "null" };
  }
});
