## 3️⃣ 권장 조치 (2주일 내)

### 3.1 ReDoS 방어

파일: `src/stdlib/builtin-regex.ts`

```typescript
// 정규식 복잡도 체크
const MAX_REGEX_COMPLEXITY = 100;
const MAX_PATTERN_LENGTH = 500;

function validateRegexPattern(pattern: string): void {
  // 길이 제한
  if (pattern.length > MAX_PATTERN_LENGTH) {
    throw new Error("Regex pattern too long");
  }

  // 복잡도 체크 (간단한 휴리스틱)
  const nestedGroups = (pattern.match(/\(/g) || []).length;
  const quantifiers = (pattern.match(/[+*{]/g) || []).length;
  const alternations = (pattern.match(/\|/g) || []).length;

  const complexity = nestedGroups + quantifiers + alternations;
  if (complexity > MAX_REGEX_COMPLEXITY) {
    throw new Error("Regex pattern too complex");
  }
}

registerBuiltin("regex_test", (args) => {
  try {
    const pattern = strVal(args[0]);
    const text = strVal(args[1]);

    validateRegexPattern(pattern);

    const re = new RegExp(pattern, 'u');
    return { tag: "bool", val: re.test(text) };
  } catch (e) {
    return { tag: "bool", val: false };
  }
});

registerBuiltin("regex_match", (args) => {
  try {
    const pattern = strVal(args[0]);
    const text = strVal(args[1]);

    validateRegexPattern(pattern);

    const re = new RegExp(pattern, 'gu');
    const matches = [...text.matchAll(re)];
    return arr(matches.map(m => str(m[0])));
  } catch (e) {
    return arr([]);
  }
});
```

