### 3.2 입력 검증 강화

새 파일: `src/stdlib/builtin-security.ts`

```typescript
// 보안 관련 빌트인 함수들
import { Value } from "../compiler";
import { registerBuiltin } from "./builtins";

function str(s: string): Value { return { tag: "str", val: s }; }
function bool(b: boolean): Value { return { tag: "bool", val: b }; }

// URL 검증
registerBuiltin("url_is_valid", (args) => {
  try {
    const urlStr = args[0].tag === "str" ? args[0].val : "";
    const url = new URL(urlStr);
    return bool(['http:', 'https:', 'ftp:'].includes(url.protocol));
  } catch {
    return bool(false);
  }
});

// 파일 경로 검증
registerBuiltin("path_is_safe", (args) => {
  const path = args[0].tag === "str" ? args[0].val : "";
  // /../ 패턴 체크
  return bool(!path.includes(".."));
});

// SQL 주입 위험 검사
registerBuiltin("sql_escape", (args) => {
  const str = args[0].tag === "str" ? args[0].val : "";
  const escaped = str
    .replace(/\\/g, "\\\\")
    .replace(/'/g, "''")
    .replace(/"/g, '\\"')
    .replace(/\0/g, "\\0")
    .replace(/\n/g, "\\n")
    .replace(/\r/g, "\\r");
  return { tag: "str", val: escaped };
});

// XSS 위험 검사
registerBuiltin("html_escape", (args) => {
  const str = args[0].tag === "str" ? args[0].val : "";
  const escaped = str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
  return { tag: "str", val: escaped };
});

// Content-Type 검증
registerBuiltin("mime_type_is_safe", (args) => {
  const mimeType = args[0].tag === "str" ? args[0].val : "";
  const unsafe = [
    'application/x-msdownload',
    'application/x-msdos-program',
    'application/x-bat',
    'application/x-cmd',
    'application/x-exe',
    'application/x-sh'
  ];
  return bool(!unsafe.includes(mimeType));
});
```

